INSERT INTO `contact` VALUES (1,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@duck.com',757130733,'prout','2023-03-25 11:52:52',33320,'Eysines'),(2,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@duck.com',757130733,'Prout','2023-03-25 11:54:09',33320,'Eysines'),(3,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@duck.com',757130733,'Prout','2023-03-25 12:04:09',33320,'Eysines'),(4,'Carli','Damien','18 Rue de la Gare','carlidamien@duck.com',757130733,'PROUT','2023-03-25 14:07:25',33320,'Eysines'),(5,'Carli','Damien','18 Rue de la Gare','carlidamien@duck.com',757130733,'CECI EST UN MESSAGE PROVENANT DU SITE WEB DE PC CLIM.','2023-03-25 14:08:08',33320,'Eysines'),(6,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@duck.com',757130733,'In auctor lobortis lacus. Phasellus viverra nulla ut metus varius laoreet.. Aenean vulputate eleifend tellus. Vivamus in erat ut urna cursus vestibulum.\r\n\r\nSuspendisse faucibus, nunc et pellentesque egestas, lacus ante convallis tellus, vitae iaculis lacus elit id tortor. Donec quam felis, ultricies nec, pellentesque eu, pretium quis, sem. Phasellus volutpat, metus eget egestas mollis, lacus lacus blandit dui, id egestas quam mauris ut lacus. Aenean posuere, tortor sed cursus feugiat, nunc augue blandit nunc, eu sollicitudin urna dolor sagittis lacus. Nullam vel sem.','2023-03-25 15:51:54',33320,'Eysines'),(7,'CROCHEZ CABINET CRICE','Cécile','8 Rue Notre Dame','crice@orange.fr',643701790,'Bonjour \r\nje viens de vous laisser un message pour une intervention 37 rue de la Manche entretien et contrôle des clims\r\nanciens locaux de in extenso c\'est M. BAILLOU qui m\'a donné vos coordonnées\r\npouvez vous me contacter pour me dire quand vous pouvez y passer\r\ncordialement\r\nCécile CROCHEZ CABINET CRICE ROYAN','2023-03-28 07:26:20',17200,'ROYAN'),(8,'Durand','Alexis','Marbella','alexis@ea2l-referencement.com',465845547,'Bonjour,\r\n\r\nNous nous permettons de vous contacter,\r\nÊtes-vous satisfait de votre référencement sur internet ?\r\nAimeriez-vous avoir une meilleure visibilité, afin d\'avoir plus de client ?\r\n\r\nN\'hésitez pas à nous contacter car nous pouvons vous aider à améliorer votre référencement à un prix très concurrentiel.\r\n\r\nA très bientôt \r\n\r\nAlexis','2023-03-31 06:50:41',29610,'Marbella'),(9,'blanch lanao','Virginie','16 la grange','virginie.bl@orange.fr',698689708,'Bonjour, vous aviez installer une pompe à chaleur air-air chez Mr MAYER à Saint Paul. Nous y habitons depuis mai 2022. Je voudrais savoir pour l\'entretien. Devez-vous le faire 1 fois par an, ou tous les 2 ans ? et votre tarif ? merci d\'avance pour votre réponse. cordialement.','2023-04-03 13:02:31',33390,'SAINT PAUL'),(10,'ROGER','Yvan','1 IMPASSE DES VANNEAUX   MOUILLESOL','yvanroger936@gmail.com',782149980,'Bonsoir Monsieur\r\nNous souhaitons faire installer la climatisation réversible\r\nVous pouvez également nous contacter sur notre tél. fixe\r\n05.16.84.79.06\r\nAvec nos remerciements','2023-04-03 17:46:24',17120,'SEMUSSAC'),(11,'denis','daniel','8A route de saint priest','daniel.denis5@numericable.fr',669081287,'bonjour, je voudrais savoir si vous faites les contrats entretien gaz et clim sur un mobil home dans un camping à saint georges de didonne et à quel prix .\r\nbien cordialement\r\nDENIS','2023-04-04 01:51:55',87590,'saint just le martel'),(12,'Durand','Alexis','Marbella','alexis@ea2l-referencement.com',465845547,'Re;) Avez-vous bien reçu mon précédent message ?\r\nJ\'aimerais juste vous aidez à augmenter vos ventes.','2023-04-04 11:12:06',29610,'Marbella'),(13,'ROBERT','JEAN','1 moulin de la lande','moulin.delalande@orange.fr',786875511,'Bonjour\r\n\r\nJe souhaiterais annuler le RDV pris pour le 17 prochain au 25 chez-vinet \r\nVeuillez m\'en excuser et merci à vous','2023-04-07 09:11:35',17120,'BOUTENAC-TOUVENT'),(14,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@protonmail.com',757130733,'coucou','2023-04-08 16:34:09',33320,'Eysines'),(15,'Damien Carli','Damien Carli','18 Rue de la Gare','carlidamien@protonmail.com',757130733,'coucou','2023-04-08 17:36:41',33320,'Eysines'),(16,'Foulques','Olivier','1 avenue des sables','sf25aero@hotmail.com',656673860,'Bonjour,\r\nJ’aurais souhaite installer une climatisation réversible, incluant 3 splits.\r\nTrès cordialement,\r\n\r\nOlivier foulques','2023-04-10 11:12:47',17110,'Saint Georges de didonne'),(17,'BARDOT','Gérard','8 rue Clément Marot','micgerba@gmail.com',613574104,'Bonjour\r\nNous envisageons la pose d\'une climatisation dans notre maison. Afin de nous engager dans ces travaux nous souhaitons être conseillés et obtenir un devis. Merci par avance de prendre contact pour un RV.\r\nCordialement\r\nMr et Mme Bardot','2023-04-13 15:10:24',17200,'ROYAN'),(18,'courtillet','Serge','10 rue des cailles','courtillet.annie@orange.fr',631042946,'Bonjour, je souhaiterais installer clim réversible dans pièce à vivre et une chambre. Pouvez vous me contacter. Merci.\r\nCdlt\r\nSerge Courtillet','2023-04-14 11:51:06',17640,'VAUX SUR MER'),(19,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Bonjour, pouvez-vous m\'envoyer un texto si vous recevez mon message ? Des gros bisous','2023-04-15 09:08:02',33320,'EYSINES'),(20,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Bonjour, pouvez-vous m\'envoyer un texto si vous recevez mon message ? Des gros bisous','2023-04-15 09:09:14',33320,'EYSINES'),(21,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Coucou, envoyez-moi un texto si vous recevez ce message. Des gros bisous.','2023-04-15 09:17:57',33320,'EYSINES'),(22,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Coucou, envoyez-moi un texto si vous recevez ce message. Des gros bisous.','2023-04-15 09:18:17',33320,'EYSINES'),(23,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Coucou, envoyez-moi un texto si vous recevez ce message. Des gros bisous.','2023-04-15 09:18:59',33320,'EYSINES'),(24,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Coucou, envoyez-moi un texto si vous recevez ce message. Des gros bisous.','2023-04-15 09:19:53',33320,'EYSINES'),(25,'Carli','Damien','18 rue de la Gare','karli.damien@gmail.com',660862734,'Coucou, envoyez-moi un texto si vous recevez ce message. Des gros bisous.','2023-04-15 09:27:42',33320,'EYSINES');
